      id: "lmp:art-7",
      numero: "7",
      caput: "São formas de violência doméstica e familiar contra a mulher, entre outras:",
      paragrafos: [],
      incisos: [{"id":"lmp:art-7-inc-I","numero":"I","texto":"a violência física, entendida como qualquer conduta que ofenda sua integridade ou saúde corporal;","alineas":[]},{"id":"lmp:art-7-inc-II","numero":"II","texto":"a violência psicológica, entendida como qualquer conduta que lhe cause dano emocional e diminuição da auto-estima ou que lhe prejudique e perturbe o pleno desenvolvimento ou que vise degradar ou controlar suas ações, comportamentos, crenças e decisões, mediante ameaça, constrangimento, humilhação, manipulação, isolamento, vigilância constante, perseguição contumaz, insulto, chantagem, ridicularização, exploração e limitação do direito de ir e vir ou qualquer outro meio que lhe cause prejuízo à saúde psicológica e à autodeterminação;","alineas":[]},{"id":"lmp:art-7-inc-II","numero":"II","texto":"a violência psicológica, entendida como qualquer conduta que lhe cause dano emocional e diminuição da autoestima ou que lhe prejudique e perturbe o pleno desenvolvimento ou que vise degradar ou controlar suas ações, comportamentos, crenças e decisões, mediante ameaça, constrangimento, humilhação, manipulação, isolamento, vigilância constante, perseguição contumaz, insulto, chantagem, violação de sua intimidade, ridicularização, exploração e limitação do direito de ir e vir ou qualquer outro meio que lhe cause prejuízo à saúde psicológica e à autodeterminação;","alineas":[]},{"id":"lmp:art-7-inc-III","numero":"III","texto":"a violência sexual, entendida como qualquer conduta que a constranja a presenciar, a manter ou a participar de relação sexual não desejada, mediante intimidação, ameaça, coação ou uso da força; que a induza a comercializar ou a utilizar, de qualquer modo, a sua sexualidade, que a impeça de usar qualquer método contraceptivo ou que a force ao matrimônio, à gravidez, ao aborto ou à prostituição, mediante coação, chantagem, suborno ou manipulação; ou que limite ou anule o exercício de seus direitos sexuais e reprodutivos;","alineas":[]},{"id":"lmp:art-7-inc-IV","numero":"IV","texto":"a violência patrimonial, entendida como qualquer conduta que configure retenção, subtração, destruição parcial ou total de seus objetos, instrumentos de trabalho, documentos pessoais, bens, valores e direitos ou recursos econômicos, incluindo os destinados a satisfazer suas necessidades;","alineas":[]},{"id":"lmp:art-7-inc-V","numero":"V","texto":"a violência moral, entendida como qualquer conduta que configure calúnia, difamação ou injúria.","alineas":[]}],
      referencias: [],
      historico: [{"versao":1,"texto":"Inc. II: a violência psicológica, entendida como qualquer conduta que lhe cause dano emocional e diminuição da autoestima ou que lhe prejudique e perturbe o pleno desenvolvimento ou que vise degradar ou controlar suas ações, comportamentos, crenças e decisões, mediante ameaça, constrangimento, humilhação, manipulação, isolamento, vigilância constante, perseguição contumaz, insulto, chantagem, violação de sua intimidade, ridicularização, exploração e limitação do direito de ir e vir ou qualquer outro meio que lhe cause prejuízo à saúde psicológica e à autodeterminação;","redacaoDadaPor":{"lei":"Redação dada pela Lei nº 13.772, de 2018","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
