      caput: "(VETADO).",
      paragrafos: [{"id":"lmp:art-12-B-p1","numero":"1","texto":"(VETADO).","alineas":[]},{"id":"lmp:art-12-B-p2","numero":"2","texto":"(VETADO.","alineas":[]},{"id":"lmp:art-12-B-p3","numero":"3","texto":"A autoridade policial poderá requisitar os serviços públicos necessários à defesa da mulher em situação de violência doméstica e familiar e de seus dependentes.","alineas":[]}],
